SELECT type
FROM source_control_configs
WHERE autoGetSource = 1;

SELECT COUNT(*) AS config_count
FROM source_control_configs
WHERE project_id = 1;

SELECT project_name, description
FROM projects
WHERE project_id IN (
  SELECT project_id
  FROM source_control_configs
);

SELECT pipeline_name
FROM ci_cd_pipelines
WHERE config_id = 1;

SELECT project_name
FROM projects
WHERE project_id IN (SELECT config_id FROM ci_cd_pipelines);

SELECT config_id
FROM source_control_configs
ORDER BY config_id;

SELECT MAX(updated_at) AS latest_update
FROM source_control_configs
WHERE project_id = 1;

SELECT config_id, COUNT(dynamic_id) AS dynamic_value_count
FROM dynamic_values
GROUP BY config_id;

SELECT project_name 
FROM projects 
ORDER BY project_id;

SELECT pipeline_name, config_id
FROM ci_cd_pipelines
ORDER BY pipeline_name;
